content.text:
 1	@use '@patternfly/patternfly/sass-utilities/all' as pf;
 2	
 3	.nb-data-consumption-card__header {
 4	  justify-content: space-between;
 5	}
 6	
 7	.nb-data-consumption-card__dropdown {
 8	  display: flex;
 9	}
10	
11	.nb-data-consumption-card__dropdown-item {
12	  max-width: 12em;
13	  @media screen and (min-width: pf.$pf-v5-global--breakpoint--lg) {
14	    min-width: 12em;
15	  }
16	  &--hide-list-style {
17	    li {
18	      list-style: none;
19	    }
20	  }
21	  &--margin {
22	    margin-right: var(--pf-t--global--spacer--100);
23	  }
24	  /* Override Options Menu item style to make it similar to Select Menu */
25	  .pf-v5-c-options-menu {
26	    --pf-v6-c-options-menu__menu-item--PaddingLeft: 0;
27	  }
28	}
29	
30	.nb-data-consumption-card__options-menu > button {
31	  width: 100%;
32	}
33	
34	.nb-data-consumption-card__chart-label {
35	  margin-top: var(--pf-t--global--spacer--300);
36	}
37	
38	.nb-data-consumption-card__chart-skeleton {
39	  margin-top: var(--pf-t--global--spacer--300);
40	  margin-bottom: var(--pf-t--global--spacer--300);
41	  width: 50%;
42	}
43	
44	.nb-data-consumption-card__chart-legend-skeleton {
45	  margin-top: var(--pf-t--global--spacer--300);
46	  width: 80%;
47	}
48	
49	.nb-perf__graph {
50	  &--short {
51	    margin-left: var(--pf-t--global--spacer--xs);
52	  }
53	  &--long {
54	    margin-left: var(--pf-t--global--spacer--500);
55	  }
56	}

